bfd_error_type
bfd_get_error (void)
{
  return bfd_error;
}

void
bfd_set_error (bfd_error_type error_tag, ...)
{
  bfd_error = error_tag;
  if (error_tag == bfd_error_on_input)
    {
      /* This is an error that occurred during bfd_close when
	 writing an archive, but on one of the input files.  */
      va_list ap;

      va_start (ap, error_tag);
      input_bfd = va_arg (ap, bfd *);
      input_error = (bfd_error_type) va_arg (ap, int);
      if (input_error >= bfd_error_on_input)
	abort ();
      va_end (ap);
    }
}

const char *
bfd_errmsg (bfd_error_type error_tag)
{
#ifndef errno
  extern int errno;
#endif
  if (error_tag == bfd_error_on_input)
    {
      char *buf;
      const char *msg = bfd_errmsg (input_error);

      if (asprintf (&buf, _(bfd_errmsgs [error_tag]), input_bfd->filename, msg)
	  != -1)
	return buf;

      /* Ick, what to do on out of memory?  */
      return msg;
    }

  if (error_tag == bfd_error_system_call)
    return xstrerror (errno);

  if (error_tag > bfd_error_invalid_error_code)
    error_tag = bfd_error_invalid_error_code;	/* sanity check */

  return _(bfd_errmsgs [error_tag]);
}

void
bfd_perror (const char *message)
{
  fflush (stdout);
  if (message == NULL || *message == '\0')
    fprintf (stderr, "%s\n", bfd_errmsg (bfd_get_error ()));
  else
    fprintf (stderr, "%s: %s\n", message, bfd_errmsg (bfd_get_error ()));
  fflush (stderr);
}

static int
_doprnt (FILE *stream, const char *format, va_list ap)
{
  const char *ptr = format;
  char specifier[128];
  int total_printed = 0;

  while (*ptr != '\0')
    {
      int result;

      if (*ptr != '%')
	{
	  /* While we have regular characters, print them.  */
	  char *end = strchr (ptr, '%');
	  if (end != NULL)
	    result = fprintf (stream, "%.*s", (int) (end - ptr), ptr);
	  else
	    result = fprintf (stream, "%s", ptr);
	  ptr += result;
	}
      else
	{
	  /* We have a format specifier!  */
	  char *sptr = specifier;
	  int wide_width = 0, short_width = 0;

	  /* Copy the % and move forward.  */
	  *sptr++ = *ptr++;

	  /* Move past flags.  */
	  while (strchr ("-+ #0", *ptr))
	    *sptr++ = *ptr++;

	  if (*ptr == '*')
	    {
	      int value = abs (va_arg (ap, int));
	      sptr += sprintf (sptr, "%d", value);
	      ptr++;
	    }
	  else
	    /* Handle explicit numeric value.  */
	    while (ISDIGIT (*ptr))
	      *sptr++ = *ptr++;

	  if (*ptr == '.')
	    {
	      /* Copy and go past the period.  */
	      *sptr++ = *ptr++;
	      if (*ptr == '*')
		{
		  int value = abs (va_arg (ap, int));
		  sptr += sprintf (sptr, "%d", value);
		  ptr++;
		}
	      else
		/* Handle explicit numeric value.  */
		while (ISDIGIT (*ptr))
		  *sptr++ = *ptr++;
	    }
	  while (strchr ("hlL", *ptr))
	    {
	      switch (*ptr)
		{
		case 'h':
		  short_width = 1;
		  break;
		case 'l':
		  wide_width++;
		  break;
		case 'L':
		  wide_width = 2;
		  break;
		default:
		  abort();
		}
	      *sptr++ = *ptr++;
	    }

	  /* Copy the type specifier, and NULL terminate.  */
	  *sptr++ = *ptr++;
	  *sptr = '\0';

	  switch (ptr[-1])
	    {
	    case 'd':
	    case 'i':
	    case 'o':
	    case 'u':
	    case 'x':
	    case 'X':
	    case 'c':
	      {
		/* Short values are promoted to int, so just copy it
		   as an int and trust the C library printf to cast it
		   to the right width.  */
		if (short_width)
		  PRINT_TYPE (int);
		else
		  {
		    /* L modifier for bfd_vma or bfd_size_type may be
		       either long long or long.  */
		    if (sptr[-2] == 'L')
		      {
			sptr[-2] = 'l';
			if (BFD_ARCH_SIZE < 64 || BFD_HOST_64BIT_LONG)
			  wide_width = 1;
			else
			  {
			    sptr[-1] = 'l';
			    *sptr++ = ptr[-1];
			    *sptr = '\0';
			  }
		      }

		    switch (wide_width)
		      {
		      case 0:
			PRINT_TYPE (int);
			break;
		      case 1:
			PRINT_TYPE (long);
			break;
		      case 2:
		      default:
#if defined (__MSVCRT__)
			sptr[-3] = 'I';
			sptr[-2] = '6';
			sptr[-1] = '4';
			*sptr++ = ptr[-1];
			*sptr = '\0';
#endif
#if defined (__GNUC__) || defined (HAVE_LONG_LONG)
			PRINT_TYPE (long long);
#else
			/* Fake it and hope for the best.  */
			PRINT_TYPE (long);
#endif
			break;
		      }
		  }
	      }
	      break;
	    case 'f':
	    case 'e':
	    case 'E':
	    case 'g':
	    case 'G':
	      {
		if (wide_width == 0)
		  PRINT_TYPE (double);
		else
		  {
#if defined (__GNUC__) || defined (HAVE_LONG_DOUBLE)
		    PRINT_TYPE (long double);
#else
		    /* Fake it and hope for the best.  */
		    PRINT_TYPE (double);
#endif
		  }
	      }
	      break;
	    case 's':
	      PRINT_TYPE (char *);
	      break;
	    case 'p':
	      PRINT_TYPE (void *);
	      break;
	    case '%':
	      fputc ('%', stream);
	      result = 1;
	      break;
	    case 'A':
	      {
		asection *sec = va_arg (ap, asection *);
		bfd *abfd;
		const char *group = NULL;
		struct coff_comdat_info *ci;

		if (sec == NULL)
		  /* Invoking %A with a null section pointer is an
		     internal error.  */
		  abort ();
		abfd = sec->owner;
		if (abfd != NULL
		    && bfd_get_flavour (abfd) == bfd_target_elf_flavour
		    && elf_next_in_group (sec) != NULL
		    && (sec->flags & SEC_GROUP) == 0)
		  group = elf_group_name (sec);
		else if (abfd != NULL
			 && bfd_get_flavour (abfd) == bfd_target_coff_flavour
			 && (ci = bfd_coff_get_comdat_section (sec->owner,
							       sec)) != NULL)
		  group = ci->name;
		if (group != NULL)
		  result = fprintf (stream, "%s[%s]", sec->name, group);
		else
		  result = fprintf (stream, "%s", sec->name);
	      }
	      break;
	    case 'B':
	      {
		bfd *abfd = va_arg (ap, bfd *);

		if (abfd == NULL)
		  /* Invoking %B with a null bfd pointer is an
		     internal error.  */
		  abort ();
		else if (abfd->my_archive
			 && !bfd_is_thin_archive (abfd->my_archive))
		  result = fprintf (stream, "%s(%s)",
				    abfd->my_archive->filename, abfd->filename);
		else
		  result = fprintf (stream, "%s", abfd->filename);
	      }
	      break;
	    default:
	      abort();
	    }
	}
      if (result == -1)
	return -1;
      total_printed += result;
    }

  return total_printed;
}

static void
error_handler_internal (const char *fmt, va_list ap)
{
  /* PR 4992: Don't interrupt output being sent to stdout.  */
  fflush (stdout);

  if (_bfd_error_program_name != NULL)
    fprintf (stderr, "%s: ", _bfd_error_program_name);
  else
    fprintf (stderr, "BFD: ");

  _doprnt (stderr, fmt, ap);

  /* On AIX, putc is implemented as a macro that triggers a -Wunused-value
     warning, so use the fputc function to avoid it.  */
  fputc ('\n', stderr);
  fflush (stderr);
}

void
_bfd_error_handler (const char *fmt, ...)
{
  va_list ap;

  va_start (ap, fmt);
  _bfd_error_internal (fmt, ap);
  va_end (ap);
}

bfd_error_handler_type
bfd_set_error_handler (bfd_error_handler_type pnew)
{
  bfd_error_handler_type pold;

  pold = _bfd_error_internal;
  _bfd_error_internal = pnew;
  return pold;
}

